+// Helpers
+// ---------------------------------------------------------------------------
+
+/// Integer square root via Newton's method.
+fn isqrt(n: u64) -> u64 {
+    if n == 0 {
+        return 0;
+    }
+    let mut x = n;
+    #[allow(clippy::manual_div_ceil)]
+    let mut y = (x + 1) / 2;
+    while y < x {
+        x = y;
+        y = (x + n / x) / 2;
+    }
+    x
+}
