+/// Report from a governance evaluation cycle.
+#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
+pub struct GovernanceReport {
+    /// Schema version.
+    pub schema_version: String,
+    /// Epoch of the evaluation.
+    pub epoch: SecurityEpoch,
