+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        write!(
+            f,
+            "DecisionReceipt({} verdict={} evidence={} parity={} epoch={})",
+            self.component,
+            self.verdict,
+            self.evidence_hashes.len(),
+            self.parity_hashes.len(),
+            self.epoch.as_u64()
+        )
+    }
