+            max_tail_regression: DEFAULT_MAX_TAIL_REGRESSION,
+            max_crash_rate: DEFAULT_MAX_CRASH_RATE,
+            required_observability_modes: vec![
+                ObservabilityMode::BudgetedCapture,
+                ObservabilityMode::ExactShadow,
